  final DateTime timestamp;
  final double amount;
  final ExpenseCategory category;
  final PaymentMethod paymentMethod;
  final String? description;
  final String? vendor;
  final List<String> tags;
  final bool isRecurring;

  const ExpenseEntry({
    required this.id,
    required this.timestamp,
    required this.amount,
    this.category = ExpenseCategory.other,
    this.paymentMethod = PaymentMethod.debit,
    this.description,
    this.vendor,
    this.tags = const [],
    this.isRecurring = false,
  });

  /// Positive = expense, negative = income (or use income category).
  bool get isExpense => !category.isIncome && amount >= 0;

  ExpenseEntry copyWith({
    String? id,
    DateTime? timestamp,
    double? amount,
    ExpenseCategory? category,
    PaymentMethod? paymentMethod,
    String? description,
    String? vendor,
    List<String>? tags,
    bool? isRecurring,
  }) {
    return ExpenseEntry(
      id: id ?? this.id,
      timestamp: timestamp ?? this.timestamp,
      amount: amount ?? this.amount,
      category: category ?? this.category,
      paymentMethod: paymentMethod ?? this.paymentMethod,
      description: description ?? this.description,
      vendor: vendor ?? this.vendor,
      tags: tags ?? this.tags,
      isRecurring: isRecurring ?? this.isRecurring,
    );
  }

  Map<String, dynamic> toJson() {
    return {
      'id': id,
      'timestamp': timestamp.toIso8601String(),
      'amount': amount,
      'category': category.name,
      'paymentMethod': paymentMethod.name,
      'description': description,
      'vendor': vendor,
      'tags': tags,
      'isRecurring': isRecurring,
    };
  }

  factory ExpenseEntry.fromJson(Map<String, dynamic> json) {
    return ExpenseEntry(
      id: json['id'] as String,
      timestamp: DateTime.tryParse(json['timestamp'] as String? ?? '') ?? DateTime.now(),
      amount: (json['amount'] as num?)?.toDouble() ?? 0.0,
      category: ExpenseCategory.values.firstWhere(
        (v) => v.name == json['category'],
        orElse: () => ExpenseCategory.other,
      ),
      paymentMethod: PaymentMethod.values.firstWhere(
        (v) => v.name == json['paymentMethod'],
        orElse: () => PaymentMethod.debit,
      ),
      description: json['description'] as String?,
      vendor: json['vendor'] as String?,
      tags: (json['tags'] as List<dynamic>?)
              ?.map((e) => e as String)
              .toList() ??
          [],
      isRecurring: json['isRecurring'] as bool? ?? false,
    );
  }

  static String encodeList(List<ExpenseEntry> entries) {
    return jsonEncode(entries.map((e) => e.toJson()).toList());
  }

  static List<ExpenseEntry> decodeList(String jsonStr) {
    final list = jsonDecode(jsonStr) as List<dynamic>;
    return list
        .map((e) => ExpenseEntry.fromJson(e as Map<String, dynamic>))
        .toList();
  }
}

