        ),
      ),
      body: TabBarView(
        controller: _tabController,
        children: [
          _BudgetTab(
            service: _service,
            entries: _demoEntries,
            year: _selectedYear,
            month: _selectedMonth,
            onMonthChanged: (y, m) => setState(() {
              _selectedYear = y;
              _selectedMonth = m;
            }),
          ),
          _SetTab(
            service: _service,
