    required this.year,
    required this.month,
  });

  @override
  Widget build(BuildContext context) {
    final theme = Theme.of(context);
    final budget = service.getBudget(year, month);
    final adherenceScore = budget != null
        ? service.getBudgetAdherenceScore(budget, entries)
        : 0;
    final savingsRate = service.getSavingsRate(entries, year, month);
    final trend = service.getMonthlyTrend(entries, months: 6);
    final overspending = budget != null
        ? service.getOverspendingCategories(budget, entries)
        : <BudgetComparison>[];
    final recommendations = budget != null
        ? service.getRecommendations(budget, entries)
        : ['Set up a budget to get personalized recommendations.'];

    return SingleChildScrollView(
      padding: const EdgeInsets.all(16),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          // Stats grid
          GridView.count(
            crossAxisCount: 2,
            shrinkWrap: true,
            physics: const NeverScrollableScrollPhysics(),
            mainAxisSpacing: 8,
            crossAxisSpacing: 8,
            childAspectRatio: 1.5,
            children: [
              _InsightCard(
                icon: Icons.speed,
                label: 'Adherence',
                value: '$adherenceScore/100',
                color: adherenceScore >= 80
                    ? Colors.green
                    : adherenceScore >= 50
                        ? Colors.orange
                        : Colors.red,
              ),
              _InsightCard(
                icon: Icons.savings,
                label: 'Savings Rate',
                value: '${(savingsRate * 100).round()}%',
                color: savingsRate >= 0.2
                    ? Colors.green
                    : savingsRate > 0
                        ? Colors.orange
                        : Colors.red,
              ),
              _InsightCard(
                icon: Icons.warning_amber,
                label: 'Over Budget',
                value: '${overspending.length}',
                color: overspending.isEmpty ? Colors.green : Colors.red,
              ),
              _InsightCard(
                icon: Icons.category,
                label: 'Categories',
                value: '${budget?.allocations.length ?? 0}',
                color: theme.colorScheme.primary,
              ),
            ],
          ),
          const SizedBox(height: 20),

          // Recommendations
          for (final rec in recommendations)
            Card(
              color: theme.colorScheme.secondaryContainer,
              margin: const EdgeInsets.only(bottom: 8),
              child: Padding(
                padding: const EdgeInsets.all(12),
                child: Row(
                  children: [
                    const Icon(Icons.lightbulb_outline, size: 24),
                    const SizedBox(width: 12),
                    Expanded(
                      child: Text(rec, style: theme.textTheme.bodyMedium),
                    ),
                  ],
                ),
              ),
            ),
          const SizedBox(height: 16),

          // 6-month trend
          Text('6-Month Trend',
              style: theme.textTheme.titleMedium
                  ?.copyWith(fontWeight: FontWeight.bold)),
          const SizedBox(height: 8),
          if (trend.isNotEmpty)
            SizedBox(
              height: 140,
              child: Row(
                crossAxisAlignment: CrossAxisAlignment.end,
                children: trend.map((point) {
                  final maxVal = trend
                      .map((p) => p.budgeted > p.actual ? p.budgeted : p.actual)
                      .reduce((a, b) => a > b ? a : b);
                  final budgetHeight =
                      maxVal > 0 ? (point.budgeted / maxVal * 100) : 0.0;
                  final actualHeight =
                      maxVal > 0 ? (point.actual / maxVal * 100) : 0.0;
                  final months = [
                    'Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun',
                    'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'
                  ];

                  return Expanded(
                    child: Padding(
                      padding: const EdgeInsets.symmetric(horizontal: 2),
                      child: Column(
                        mainAxisAlignment: MainAxisAlignment.end,
                        children: [
                          Row(
                            mainAxisAlignment: MainAxisAlignment.center,
                            crossAxisAlignment: CrossAxisAlignment.end,
                            children: [
                              // Budget bar
                              Container(
                                width: 12,
                                height: budgetHeight,
                                decoration: BoxDecoration(
                                  color: theme.colorScheme.primary
                                      .withOpacity(0.4),
                                  borderRadius: BorderRadius.circular(2),
                                ),
                              ),
                              const SizedBox(width: 2),
                              // Actual bar
                              Container(
                                width: 12,
                                height: actualHeight,
                                decoration: BoxDecoration(
                                  color: actualHeight > budgetHeight
                                      ? Colors.red
                                      : Colors.green,
                                  borderRadius: BorderRadius.circular(2),
                                ),
                              ),
                            ],
                          ),
                          const SizedBox(height: 4),
                          Text(
                            months[point.month - 1],
                            style: theme.textTheme.labelSmall,
                          ),
                        ],
                      ),
                    ),
                  );
                }).toList(),
              ),
            ),
          // Legend
          Padding(
            padding: const EdgeInsets.only(top: 4),
            child: Row(
              mainAxisAlignment: MainAxisAlignment.center,
              children: [
                Container(
                  width: 12,
                  height: 12,
                  decoration: BoxDecoration(
                    color: theme.colorScheme.primary.withOpacity(0.4),
                    borderRadius: BorderRadius.circular(2),
                  ),
                ),
                const SizedBox(width: 4),
                Text('Budget', style: theme.textTheme.labelSmall),
                const SizedBox(width: 12),
                Container(
                  width: 12,
                  height: 12,
                  decoration: BoxDecoration(
                    color: Colors.green,
                    borderRadius: BorderRadius.circular(2),
                  ),
                ),
                const SizedBox(width: 4),
                Text('Actual', style: theme.textTheme.labelSmall),
              ],
            ),
          ),
          const SizedBox(height: 20),

          // Over-budget categories
          if (overspending.isNotEmpty) ...[
            Text('Over Budget Categories',
                style: theme.textTheme.titleMedium
                    ?.copyWith(fontWeight: FontWeight.bold)),
            const SizedBox(height: 8),
            ...overspending.map((c) => Card(
                  color: Colors.red.withOpacity(0.1),
                  child: ListTile(
                    leading: Text(c.category.emoji,
                        style: const TextStyle(fontSize: 24)),
                    title: Text(c.category.label),
                    subtitle: Text(
                      'Over by \$${(c.spent - c.budgeted).toStringAsFixed(0)} (${(c.percentUsed * 100).round()}% used)',
                    ),
                    trailing: Text(
                      '\$${c.spent.toStringAsFixed(0)}',
                      style: theme.textTheme.bodyLarge?.copyWith(
                        fontWeight: FontWeight.bold,
                        color: Colors.red,
                      ),
                    ),
                  ),
                )),
          ],
        ],
      ),
    );
  }
}

class _InsightCard extends StatelessWidget {
  final IconData icon;
  final String label;
  final String value;
  final Color color;

  const _InsightCard({
    required this.icon,
    required this.label,
    required this.value,
    required this.color,
  });

  @override
  Widget build(BuildContext context) {
    return Card(
      child: Padding(
        padding: const EdgeInsets.all(12),
        child: Column(
          mainAxisAlignment: MainAxisAlignment.center,
          children: [
            Icon(icon, color: color, size: 24),
            const SizedBox(height: 4),
            Text(value,
                style: Theme.of(context)
                    .textTheme
                    .titleMedium
                    ?.copyWith(fontWeight: FontWeight.bold)),
            Text(label, style: Theme.of(context).textTheme.bodySmall),
          ],
        ),
      ),
    );
  }
}
